 1	import { Map as ImmutableMap } from 'immutable';
 2	import * as React from 'react';
 3	import { useDispatch, useSelector } from 'react-redux';
 4	import { Label, LabelGroup } from '@patternfly/react-core';
 5	import { CodeIcon, InfoCircleIcon } from '@patternfly/react-icons';
 6	
 7	import { openToolSet } from '../redux-actions';
 8	import { State } from '../redux-reducers';
 9	
10	type ToolProps = {
11	  entryIndex: number;
12	  toolID: string;
13	};
14	
15	const ToolLabel: React.FC<ToolProps> = ({ entryIndex, toolID }) => {
16	  const dispatch = useDispatch();
17	
18	  const tool: ImmutableMap<string, unknown> = useSelector((s: State) =>
19	    s.plugins?.ols?.getIn(['chatHistory', entryIndex, 'tools', toolID]),
20	  );
21	
22	  const onClick = React.useCallback(() => {
23	    dispatch(openToolSet(entryIndex, toolID));
24	  }, [dispatch, entryIndex, toolID]);
25	
26	  const isError = tool.get('status') === 'error';
27	
28	  return (
29	    <Label
30	      color={isError ? 'red' : undefined}
31	      icon={isError ? <InfoCircleIcon /> : <CodeIcon />}
32	      onClick={onClick}
33	      textMaxWidth="16ch"
34	    >
35	      {tool.get('name')}
36	    </Label>
37	  );
38	};
39	
40	type ResponseToolsProps = {
41	  entryIndex: number;
42	};
43	
44	const ResponseTools: React.FC<ResponseToolsProps> = ({ entryIndex }) => {
45	  const tools: ImmutableMap<string, ImmutableMap<string, unknown>> = useSelector((s: State) =>
46	    s.plugins?.ols?.getIn(['chatHistory', entryIndex, 'tools']),
47	  );
48	
49	  return (
50	    <div className="ols-plugin__references">
51	      <LabelGroup numLabels={4}>
52	        {tools.keySeq().map((toolID) => (
53	          <ToolLabel entryIndex={entryIndex} key={toolID} toolID={toolID} />
54	        ))}
55	      </LabelGroup>
56	    </div>
57	  );
58	};
59	
60	export default ResponseTools;

